import asyncio
import aiohttp

async def fetch_json(session, url):
    async with session.get(url) as response:
        return await response.json()

async def get_dashboard_data(user_id):
    base = "https://api.example.com"

    async with aiohttp.ClientSession() as session:
        profile, orders, notifications = await asyncio.gather(
            fetch_json(session, f"{base}/users/{user_id}"),
            fetch_json(session, f"{base}/orders?user={user_id}"),
            fetch_json(session, f"{base}/notifications/{user_id}"),
            return_exceptions=True  # Don't let one failure kill all three
        )

    # Handle partial failures gracefully
    if isinstance(profile, Exception):
        profile = {"name": "Unknown"}
    if isinstance(orders, Exception):
        orders = []
    if isinstance(notifications, Exception):
        notifications = []

    return {"profile": profile, "orders": orders, "notifications": notifications}

asyncio.run(get_dashboard_data(42))
